import{_ as t,o as i,c as e,O as o}from"./chunks/framework.bdcb0ee1.js";const d=JSON.parse('{"title":"Notifications","description":"","frontmatter":{},"headers":[],"relativePath":"userguide/notifications.md","filePath":"userguide/notifications.md","lastUpdated":1773167467000}'),a={name:"userguide/notifications.md"},n=o('<h1 id="notifications" tabindex="-1">Notifications <a class="header-anchor" href="#notifications" aria-label="Permalink to &quot;Notifications&quot;">​</a></h1><p>Notifications keep you informed about activity on the board that is relevant to you.</p><nav class="table-of-contents"><ul><li><a href="#notification-types">Notification types</a></li><li><a href="#viewing-notifications">Viewing notifications</a></li><li><a href="#managing-notification-preferences">Managing notification preferences</a></li><li><a href="#watching-topics">Watching topics</a></li></ul></nav><h2 id="notification-types" tabindex="-1">Notification types <a class="header-anchor" href="#notification-types" aria-label="Permalink to &quot;Notification types&quot;">​</a></h2><p>You may receive notifications for the following events:</p><ul><li><strong>Topic reply</strong> — someone replied to a topic you are watching.</li><li><strong>Mention</strong> — another member mentioned you in a post using <code>@yourusername</code>.</li><li><strong>Reaction</strong> — someone reacted to one of your posts.</li><li><strong>Private message</strong> — you received a new private message.</li><li><strong>Achievement unlocked</strong> — you earned an achievement.</li></ul><h2 id="viewing-notifications" tabindex="-1">Viewing notifications <a class="header-anchor" href="#viewing-notifications" aria-label="Permalink to &quot;Viewing notifications&quot;">​</a></h2><p>Click the notification icon in the navigation bar to see your recent notifications. Each entry shows a summary of the event, who triggered it and a link to the relevant content.</p><img width="1975" height="843" alt="image" src="https://github.com/user-attachments/assets/ac44ede2-aee1-4751-9044-fefafbf8bc07"><h2 id="managing-notification-preferences" tabindex="-1">Managing notification preferences <a class="header-anchor" href="#managing-notification-preferences" aria-label="Permalink to &quot;Managing notification preferences&quot;">​</a></h2><p>You can control which notifications you receive by visiting <strong>Edit Profile</strong> and navigating to the notification settings. The following options are available:</p><ul><li><strong>Email on topic reply</strong> — receive an email when someone replies to a watched topic.</li><li><strong>Weekly digest</strong> — receive a compiled summary of board activity each week.</li><li><strong>Auto-watch replies</strong> — automatically watch any topic you reply to.</li></ul><img width="1937" height="730" alt="image" src="https://github.com/user-attachments/assets/3377f24d-f2e8-410e-b455-3935189f4478"><h2 id="watching-topics" tabindex="-1">Watching topics <a class="header-anchor" href="#watching-topics" aria-label="Permalink to &quot;Watching topics&quot;">​</a></h2><p>When you watch a topic, you receive a notification each time someone posts a new reply. You automatically watch topics that you create. If the <strong>Auto-watch replies</strong> option is enabled, you will also watch topics that you reply to.</p><p>To manually watch or unwatch a topic, click the <strong>Watch</strong> / <strong>Unwatch</strong> button at the top of the topic page.</p>',16),s=[n];function c(r,l,h,f,g,p){return i(),e("div",null,s)}const m=t(a,[["render",c]]);export{d as __pageData,m as default};
